import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const response = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/wait-for-kubernetes-job-completed/result');
  const body = await response.json();

  const status = body?.status || {};
  const succeeded = Number(status.succeeded || 0);
  const failed = Number(status.failed || 0);

  if (failed > 0 || succeeded === 0) {
    throw new Error('Kubernetes remediation did not complete successfully. succeeded=' + succeeded + ', failed=' + failed);
  }

  return body;
}
